#include <unordered_map>
#include <climits>
#include <algorithm>

long long solve(long long n) {
    std::unordered_map<int, int> frequency;

    if (n == 0) {
        return 0;
    }

    while (n > 0) {
        int digit = n % 10;
        frequency[digit]++;
        n /= 10;
    }

    int min_freq = INT_MAX;
    int result = 10; // Initialize with a value larger than any digit (0-9)

    for (const auto& pair : frequency) {
        if (pair.second < min_freq) {
            min_freq = pair.second;
            result = pair.first;
        } else if (pair.second == min_freq && pair.first < result) {
            result = pair.first;
        }
    }

    return result;
}
